import React, { useState } from "react";
import Dashboard from "./components/Dashboard";
import UploadContainer from "./components/UploadContainer";
import { buildDownloadUrl, uploadAndPredict } from "./services/api";
import "./styles/dashboard.css";

function App() {
	const [loading, setLoading] = useState(false);
	const [error, setError] = useState("");
	const [summary, setSummary] = useState(null);
	const [predictions, setPredictions] = useState([]);
	const [jobId, setJobId] = useState("");

	const handleUpload = async (file) => {
		setLoading(true);
		setError("");

		try {
			const response = await uploadAndPredict(file);
			setSummary(response.summary);
			setPredictions(response.predictions_preview || []);
			setJobId(response.job_id || "");
		} catch (uploadError) {
			const detail =
				uploadError?.response?.data?.detail ||
				"Failed to process file. Verify file format and required columns.";
			setError(detail);
		} finally {
			setLoading(false);
		}
	};

	return (
		<main className="app-shell">
			<header>
				<h1>SmartContainer Risk Engine</h1>
				<p>AI-assisted anomaly detection and risk prioritization for container shipments.</p>
			</header>

			<UploadContainer onSubmit={handleUpload} loading={loading} />

			{error && <section className="card error-card">{error}</section>}

			{jobId && (
				<section className="card result-card">
					<strong>Batch Job ID:</strong> {jobId}
					<a href={buildDownloadUrl(jobId)} target="_blank" rel="noreferrer">
						Download Prediction CSV
					</a>
				</section>
			)}

			<Dashboard summary={summary} predictions={predictions} />
		</main>
	);
}

export default App;
